  ('bookkeeper-moex-00829', 'bookkeeper', 'bookkeeper-moex-108-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '未記明理由之書面行政處分，且非屬行政程序法第 111 條之無效者，依行政程序法規定，下列何者敘述 錯誤？', '["未限制人民之權益者，得不記明理由", "如必須記明理由者，該瑕疵行政處分更正後即可完善", "已於事後記明之補正行為，僅得於訴願程序終結前為之", "已於事後記明之補正行為，得不經訴願程序者，僅得於向行政法院起訴前為之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "ffaf06180d77", "answer_pdf_sha1": "5bdaf7f539a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
