  ('bookkeeper-moex-00831', 'bookkeeper', 'bookkeeper-moex-108-12108af6', 'sub-bookkeeper-04', NULL, 'single_choice', '公法上之請求權，於請求權人為甲行政機關，無法律另有規定，至107年12月31日止已經過4年，甲', '["被撤銷或廢止或其他事由 而溯及既往失效時、", "不得訴請撤銷或因其他原因失其效力後，則該請求權至何時時效完成而消滅？", "", "109年1月1日消滅、"]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:24+00:00", "source_pdf_sha1": "ffaf06180d77", "answer_pdf_sha1": "5bdaf7f539a6", "source_family": "moex-gov-tw", "moex": {"exam_code": "108180", "c": "602", "s": "1202", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "記帳相關法規概要", "year": "108", "exam_name": "108年專門職業及技術人員高等考試建築師、技師、第二次食品技師考試暨普通考試不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "bookkeeper", "db_exam_id": "bookkeeper"}'::jsonb, NULL),
